// src/pages/MainPage/index.jsx

import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import { fetchCategories } from '../../store/slices/categoriesSlice';
import { fetchAllProducts } from '../../store/slices/productsSlice';
import CategoryItem from '../../components/CategoryItem';
import ProductCard from '../../components/ProductCard';
import CouponForm from '../../components/CouponForm';
import Button from '../../components/UI/Button';
import s from './MainPage.module.css';

// --- ВАЖНО: ПРОВЕРЬ НАЗВАНИЯ ФАЙЛОВ НИЖЕ ---

// 1. Проверь, как точно называется твой файл баннера. 
// Если он .jpg, поменяй .png на .jpg здесь:
import bannerImage from '../../assets/images/garden_banner.png'; 

// 2. Импортируем картинку для рук (раз ты ее используешь ниже).
// Убедись, что файл hands.png (или .jpg) лежит в папке assets/images
import handsImage from '../../assets/images/hands.png'; 
// Если такой картинки пока нет, закомментируй строку выше и удали использование ниже.

const MainPage = () => {
  const dispatch = useDispatch();

  const categories = useSelector(state => state.categories.list).slice(0, 4);
  const categoriesStatus = useSelector(state => state.categories.status);

  const allProducts = useSelector(state => state.products.list);
  const discountedProducts = allProducts
    .filter(p => p.discont_price !== null && p.discont_price < p.price)
    .slice(0, 4);

  useEffect(() => {
    if (categoriesStatus === 'idle') dispatch(fetchCategories());
    dispatch(fetchAllProducts());
  }, [dispatch, categoriesStatus]);

  return (
    <div className={s.mainContainer}>

      {/* Секция Баннера */}
      <section 
        className={s.heroBanner}
        style={{ backgroundImage: `url(${bannerImage})` }} 
      >
        <div className={s.heroContent}>
          <h1>Amazing Discounts on Garden Products!</h1>
          <Button className={s.heroBtn}>Check out</Button>
        </div>
      </section>

      {/* Секция Категорий */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
          <h2>Categories</h2>
          <div className={s.line}></div>
          <Link to="/categories">
            <button className={s.outlineBtn}>All categories</button>
          </Link>
        </div>

        <div className={s.categoriesGrid}>
          {categoriesStatus === 'loading' ? <p>Loading...</p> : 
            categories.map(cat => (
              <CategoryItem key={cat.id} {...cat} />
            ))
          }
        </div>
      </section>

      {/* Секция Скидки */}
      <section className={s.discountSection}>
        <div className={s.discountContent}>
           <h2>5% off on the first order</h2>
           <div className={s.discountLayout}>
              <div className={s.imageWrapper}>
                 {/* Здесь используем handsImage, который мы импортировали выше */}
                 <img src={handsImage} alt="Hands" />
              </div>
              <div className={s.formWrapper}>
                 <CouponForm className={s.customForm} />
              </div>
           </div>
        </div>
      </section>

      {/* Секция Распродажи */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
            <h2>Sale</h2>
            <div className={s.line}></div>
            <Link to="/products">
                <button className={s.outlineBtn}>All sales</button>
            </Link>
        </div>
        <div className={s.productsGrid}>
          {discountedProducts.map(product => (
            <ProductCard key={product.id} {...product} />
          ))}
        </div>
      </section>

    </div>
  );
};

export default MainPage;
